# Generated by openai (gpt-5.2)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
  agent any

  options {
    timestamps()
    ansiColor('xterm')
    disableConcurrentBuilds()
    buildDiscarder(logRotator(numToKeepStr: '30', artifactNumToKeepStr: '10'))
    timeout(time: 2, unit: 'HOURS')
  }

  parameters {
    choice(
      name: 'SHELL',
      choices: ['bash', 'sh'],
      description: 'Shell to use for executing commands.'
    )

    booleanParam(
      name: 'USE_WORKSPACE_SCRIPTS',
      defaultValue: false,
      description: 'If true, run scripts from files in the workspace (safer than free-form).'
    )

    string(
      name: 'BUILD_SCRIPT_PATH',
      defaultValue: 'ci/build.sh',
      description: 'Workspace script path for build (used when USE_WORKSPACE_SCRIPTS=true).'
    )

    string(
      name: 'TEST_SCRIPT_PATH',
      defaultValue: 'ci/test.sh',
      description: 'Workspace script path for tests (used when USE_WORKSPACE_SCRIPTS=true).'
    )

    string(
      name: 'DEPLOY_SCRIPT_PATH',
      defaultValue: 'ci/deploy.sh',
      description: 'Workspace script path for deploy (used when USE_WORKSPACE_SCRIPTS=true).'
    )

    text(
      name: 'BUILD_COMMANDS',
      defaultValue: 'echo "No build commands provided"\n',
      description: 'Shell commands for build stage (used when USE_WORKSPACE_SCRIPTS=false).'
    )

    text(
      name: 'TEST_COMMANDS',
      defaultValue: 'echo "No test commands provided"\n',
      description: 'Shell commands for test stage (used when USE_WORKSPACE_SCRIPTS=false).'
    )

    text(
      name: 'DEPLOY_COMMANDS',
      defaultValue: 'echo "No deploy commands provided"\n',
      description: 'Shell commands for deploy stage (used when USE_WORKSPACE_SCRIPTS=false).'
    )

    booleanParam(
      name: 'RUN_BUILD',
      defaultValue: true,
      description: 'Run build stage.'
    )

    booleanParam(
      name: 'RUN_TESTS',
      defaultValue: true,
      description: 'Run test stage.'
    )

    booleanParam(
      name: 'RUN_DEPLOY',
      defaultValue: false,
      description: 'Run deploy stage.'
    )

    booleanParam(
      name: 'FAIL_ON_EMPTY',
      defaultValue: true,
      description: 'Fail if a selected stage has no commands/script.'
    )

    booleanParam(
      name: 'ALLOW_UNSAFE_COMMANDS',
      defaultValue: false,
      description: 'If false, blocks some obviously dangerous patterns in free-form commands.'
    )
  }

  environment {
    CI = 'true'
  }

  stages {
    stage('Checkout') {
      steps {
        checkout scm
      }
    }

    stage('Build') {
      when { expression { return params.RUN_BUILD } }
      steps {
        script {
          runUserStep('Build', params.BUILD_COMMANDS, params.BUILD_SCRIPT_PATH)
        }
      }
    }

    stage('Test') {
      when { expression { return params.RUN_TESTS } }
      steps {
        script {
          runUserStep('Test', params.TEST_COMMANDS, params.TEST_SCRIPT_PATH)
        }
      }
    }

    stage('Deploy') {
      when { expression { return params.RUN_DEPLOY } }
      steps {
        script {
          runUserStep('Deploy', params.DEPLOY_COMMANDS, params.DEPLOY_SCRIPT_PATH)
        }
      }
    }
  }

  post {
    always {
      echo "Build result: ${currentBuild.currentResult}"
    }
  }
}

def runUserStep(String label, String inlineCommands, String scriptPath) {
  String shell = (params.SHELL ?: 'bash').trim()
  if (!(shell in ['bash', 'sh'])) {
    error("Unsupported SHELL: ${shell}")
  }

  if (params.USE_WORKSPACE_SCRIPTS) {
    String p = (scriptPath ?: '').trim()
    if (!p) {
      if (params.FAIL_ON_EMPTY) error("${label}: Script path is empty.")
      echo "${label}: No script path provided; skipping."
      return
    }
    if (!fileExists(p)) {
      error("${label}: Script not found in workspace: ${p}")
    }
    String cmd = (shell == 'bash')
      ? "set -euo pipefail\nchmod +x '${p}'\n'${p}'\n"
      : "set -eu\nchmod +x '${p}'\n'${p}'\n"
    sh(label: "${label} (script: ${p})", script: cmd)
    return
  }

  String cmds = (inlineCommands ?: '').trim()
  if (!cmds) {
    if (params.FAIL_ON_EMPTY) error("${label}: No commands provided.")
    echo "${label}: No commands provided; skipping."
    return
  }

  if (!params.ALLOW_UNSAFE_COMMANDS) {
    def forbidden = [
      ~/(\s|^)(rm\s+-rf\s+\/)(\s|$)/,
      ~/(\s|^)(rm\s+-rf\s+--no-preserve-root)(\s|$)/,
      ~/(\s|^)(mkfs\.)/,
      ~/(\s|^)(dd\s+if=\/dev\/zero\s+of=\/dev\/)/,
      ~/(\s|^)(:\s*\(\)\s*\{\s*:\s*\|\s*:\s*;\s*\}\s*;)/, // fork bomb
      ~/(\s|^)(shutdown|reboot|halt)(\s|$)/
    ]
    for (p in forbidden) {
      if ((cmds =~ p).find()) {
        error("${label}: Command blocked by safety policy. Set ALLOW_UNSAFE_COMMANDS=true to override.")
      }
    }
  }

  String header = (shell == 'bash') ? "set -euo pipefail\n" : "set -eu\n"
  sh(label: "${label} (inline commands)", script: header + cmds + "\n")
}